aws sqs start-message-move-task \
  --source-arn arn:aws:sqs:us-east-1:123:my-queue-dlq \
  --destination-arn arn:aws:sqs:us-east-1:123:my-queue \
  --max-number-of-messages-per-second 10

# Check move task status
aws sqs list-message-move-tasks \
  --source-arn arn:aws:sqs:us-east-1:123:my-queue-dlq
```

Enable `FunctionResponseTypes: [ReportBatchItemFailures]` in SAM/CloudFormation to use partial batch failures.

Starting with Node.js 18, unhandled promise rejections crash the Lambda process. In Node.js 16 and earlier, they were logged but ignored.

```javascript
// This crashes in Node.js 18+ Lambda runtime
export const handler = async (event) => {
  // Fire-and-forget async operation with no error handling
  someAsyncOperation(); // No await, no .catch()
  // If someAsyncOperation rejects, Lambda crashes

  return { statusCode: 200, body: 'OK' };
};

// Fix: always handle async errors
export const handler = async (event) => {
  // Option 1: await it
  await someAsyncOperation();

  // Option 2: catch the error
  someAsyncOperation().catch(err => {
    console.error('Background task failed:', err);
  });

  // Option 3: global handler (last resort)
  process.on('unhandledRejection', (err) => {
    console.error('Unhandled rejection:', err);
    // Don't process.exit — Lambda handles this
  });

  return { statusCode: 200, body: 'OK' };
};
```

This is the #1 cause of mysterious Lambda crashes when migrating from Node.js 16 to 18+. Search for fire-and-forget promises in your codebase and add proper error handling.

Single-table design stores multiple entity types in one table, using generic partition and sort keys with prefixes to support multiple access patterns.

```javascript
// Table: PK (String), SK (String), GSI1PK, GSI1SK

// User entity
{
  PK: 'USER#user123',
  SK: 'PROFILE',
  GSI1PK: 'USER#user123',
  GSI1SK: 'PROFILE',
  name: 'Alice',
  email: 'alice@example.com',
  entityType: 'User',
}

// Order entity
{
  PK: 'USER#user123',
  SK: 'ORDER#2024-01-15#ord456',
  GSI1PK: 'ORDER#ord456',
  GSI1SK: 'ORDER',
  total: 99.99,
  status: 'shipped',
  entityType: 'Order',
}

// Access patterns:
// 1. Get user profile: Query PK='USER#user123', SK='PROFILE'
// 2. Get user's orders: Query PK='USER#user123', SK begins_with 'ORDER#'
// 3. Get user's orders in date range: Query PK='USER#user123', SK between 'ORDER#2024-01' and 'ORDER#2024-12'
// 4. Get order by ID: Query GSI1PK='ORDER#ord456'

const userOrders = await ddb.send(new QueryCommand({
  TableName: 'AppTable',
  KeyConditionExpression: 'PK = :pk AND begins_with(SK, :sk)',
  ExpressionAttributeValues: {
    ':pk': 'USER#user123',
    ':sk': 'ORDER#',
  },
}));
```

Pros: single query returns related entities, fewer tables to manage, lower cost. Cons: harder to understand, requires upfront access pattern analysis, GSI overhead. Start with single-table for new projects with well-defined access patterns.

Lambda Powertools provides production-ready observability with minimal boilerplate.

```javascript
import { Logger } from '@aws-lambda-powertools/logger';
import { Tracer } from '@aws-lambda-powertools/tracer';
import { Metrics, MetricUnit } from '@aws-lambda-powertools/metrics';
import middy from '@middy/core';
import { injectLambdaContext } from '@aws-lambda-powertools/logger/middleware';
import { captureLambdaHandler } from '@aws-lambda-powertools/tracer/middleware';
import { logMetrics } from '@aws-lambda-powertools/metrics/middleware';

const logger = new Logger({ serviceName: 'order-api' });
const tracer = new Tracer({ serviceName: 'order-api' });
const metrics = new Metrics({ namespace: 'OrderAPI', serviceName: 'order-api' });

const lambdaHandler = async (event) => {
  // Structured logging with correlation IDs
  logger.appendKeys({ orderId: event.pathParameters.id });
  logger.info('Processing order');

  // Custom metrics
  metrics.addMetric('OrderProcessed', MetricUnit.Count, 1);
  metrics.addMetric('ProcessingTime', MetricUnit.Milliseconds, 150);

  // Custom trace segments
  const subsegment = tracer.getSegment().addNewSubsegment('fetchOrder');
  const order = await fetchOrder(event.pathParameters.id);
  subsegment.close();

  return { statusCode: 200, body: JSON.stringify(order) };
};

export const handler = middy(lambdaHandler)
  .use(injectLambdaContext(logger, { clearState: true }))
  .use(captureLambdaHandler(tracer))
  .use(logMetrics(metrics));
```

Powertools auto-captures cold start metrics, adds request IDs to logs, and traces AWS SDK calls. The `clearState` option prevents log keys from leaking between invocations.

