Use the middy middleware framework to separate cross-cutting concerns (auth, validation, error handling) from business logic.

```javascript
import middy from '@middy/core';
import httpJsonBodyParser from '@middy/http-json-body-parser';
import httpErrorHandler from '@middy/http-error-handler';
import validator from '@middy/validator';
import { transpileSchema } from '@middy/validator/transpile';
import createError from 'http-errors';

// Input validation schema
const inputSchema = transpileSchema({
  type: 'object',
  required: ['body'],
  properties: {
    body: {
      type: 'object',
      required: ['name', 'email'],
      properties: {
        name: { type: 'string', minLength: 1 },
        email: { type: 'string', format: 'email' },
      },
    },
  },
});

// Custom auth middleware
const authMiddleware = () => ({
  before: async (request) => {
    const token = request.event.headers?.authorization;
    if (!token) throw createError(401, 'Missing authorization header');
    try {
      request.event.user = await verifyJwt(token.replace('Bearer ', ''));
    } catch {
      throw createError(401, 'Invalid token');
    }
  },
});

// Pure business logic
const businessHandler = async (event) => {
  const { name, email } = event.body; // Already parsed
  const user = event.user; // Set by auth middleware
  const result = await createUser({ name, email, createdBy: user.sub });
  return { statusCode: 201, body: JSON.stringify(result) };
};

export const handler = middy(businessHandler)
  .use(httpJsonBodyParser())
  .use(authMiddleware())
  .use(validator({ eventSchema: inputSchema }))
  .use(httpErrorHandler());
```

Middy processes middleware in order (before) and reverse order (after/onError). This pattern keeps handlers clean and testable.

