const errorAlarm = new Alarm(this, 'LambdaErrorAlarm', {
  metric: fn.metricErrors({
    period: cdk.Duration.minutes(5),
    statistic: 'Sum',
  }),
  threshold: 5,
  evaluationPeriods: 2,
  comparisonOperator: ComparisonOperator.GREATER_THAN_THRESHOLD,
  treatMissingData: cloudwatch.TreatMissingData.NOT_BREACHING,
});

// Duration alarm (approaching timeout)
const durationAlarm = new Alarm(this, 'LambdaDurationAlarm', {
  metric: fn.metricDuration({
    period: cdk.Duration.minutes(5),
    statistic: 'p99',
  }),
  threshold: 8000, // 8 seconds (function timeout is 10s)
  evaluationPeriods: 3,
});

// Throttle alarm
const throttleAlarm = new Alarm(this, 'LambdaThrottleAlarm', {
  metric: fn.metricThrottles({ period: cdk.Duration.minutes(1) }),
  threshold: 1,
  evaluationPeriods: 1,
});

// SNS notification
const topic = new sns.Topic(this, 'AlarmTopic');
topic.addSubscription(new subscriptions.EmailSubscription('ops@example.com'));
errorAlarm.addAlarmAction(new cloudwatchActions.SnsAction(topic));

// Dashboard
const dashboard = new Dashboard(this, 'ApiDashboard');
dashboard.addWidgets(
  new GraphWidget({
    title: 'Invocations & Errors',
    left: [fn.metricInvocations(), fn.metricErrors()],
    period: cdk.Duration.minutes(5),
  }),
  new GraphWidget({
    title: 'Duration (p50, p99)',
    left: [
      fn.metricDuration({ statistic: 'p50' }),
      fn.metricDuration({ statistic: 'p99' }),
    ],
  }),
);
```

Minimum alarms for production: error count, p99 duration, throttle count, concurrent executions. Add DynamoDB throttle and SQS dead letter queue depth alarms for a complete picture.

A production VPC with proper subnet tiers for different workload types.

```typescript
const vpc = new ec2.Vpc(this, 'ProdVpc', {
  ipAddresses: ec2.IpAddresses.cidr('10.0.0.0/16'),
  maxAzs: 3,
  natGateways: 2, // 2 for HA, 1 for cost savings

  subnetConfiguration: [
    {
      name: 'Public',
      subnetType: ec2.SubnetType.PUBLIC,
      cidrMask: 24,  // 251 IPs per AZ — for ALBs, NAT Gateways, bastion
    },
    {
      name: 'Private',
      subnetType: ec2.SubnetType.PRIVATE_WITH_EGRESS,
      cidrMask: 20,  // 4091 IPs per AZ — for ECS, Lambda, EC2
    },
    {
      name: 'Isolated',
      subnetType: ec2.SubnetType.PRIVATE_ISOLATED,
      cidrMask: 24,  // 251 IPs per AZ — for RDS, ElastiCache
    },
  ],

  // Flow logs for debugging
  flowLogs: {
    flowLog: {
      destination: ec2.FlowLogDestination.toCloudWatchLogs(),
      trafficType: ec2.FlowLogTrafficType.REJECT,
    },
  },
});

// VPC endpoints for cost savings
vpc.addGatewayEndpoint('S3Endpoint', {
  service: ec2.GatewayVpcEndpointAwsService.S3,
});
vpc.addGatewayEndpoint('DynamoEndpoint', {
  service: ec2.GatewayVpcEndpointAwsService.DYNAMODB,
});
```

Subnet types:
- **Public**: Has internet gateway route. For load balancers, bastion hosts, NAT Gateways.
- **Private with egress**: Routes to internet via NAT Gateway. For application servers, Lambda, ECS tasks.
- **Isolated**: No internet access at all. For databases, caches — maximum security.

A complete ECS Fargate configuration with ALB, auto-scaling, and health checks.

```typescript
const cluster = new ecs.Cluster(this, 'Cluster', { vpc });

const taskDef = new ecs.FargateTaskDefinition(this, 'TaskDef', {
  memoryLimitMiB: 512,
  cpu: 256,
  runtimePlatform: {
    cpuArchitecture: ecs.CpuArchitecture.ARM64, // Graviton — 20% cheaper
    operatingSystemFamily: ecs.OperatingSystemFamily.LINUX,
  },
});

const container = taskDef.addContainer('app', {
  image: ecs.ContainerImage.fromEcrRepository(repo, 'latest'),
  logging: ecs.LogDrivers.awsLogs({
    streamPrefix: 'app',
    logRetention: logs.RetentionDays.ONE_MONTH,
  }),
  healthCheck: {
    command: ['CMD-SHELL', 'curl -f http://localhost:3000/health || exit 1'],
    interval: cdk.Duration.seconds(30),
    timeout: cdk.Duration.seconds(5),
    retries: 3,
    startPeriod: cdk.Duration.seconds(60),
  },
  environment: {
    NODE_ENV: 'production',
  },
  secrets: {
    DATABASE_URL: ecs.Secret.fromSecretsManager(dbSecret, 'url'),
  },
});
container.addPortMappings({ containerPort: 3000 });

const service = new ecsPatterns.ApplicationLoadBalancedFargateService(this, 'Service', {
  cluster,
  taskDefinition: taskDef,
  desiredCount: 2,
  healthCheckGracePeriod: cdk.Duration.seconds(120),
  circuitBreaker: { enable: true, rollback: true },
});

// Auto-scaling
const scaling = service.service.autoScaleTaskCount({
  minCapacity: 2,
  maxCapacity: 20,
});
scaling.scaleOnCpuUtilization('CpuScaling', {
  targetUtilizationPercent: 60,
  scaleInCooldown: cdk.Duration.minutes(5),
});
```

The circuit breaker rolls back to the previous task definition if new tasks fail to start. `healthCheckGracePeriod` prevents the ALB from killing tasks during startup.

Use OIDC federation instead of long-lived AWS access keys in GitHub Actions. No secrets to rotate.

```typescript
// CDK — create OIDC provider and deployment role
const githubProvider = new iam.OpenIdConnectProvider(this, 'GitHubOIDC', {
  url: 'https://token.actions.githubusercontent.com',
  clientIds: ['sts.amazonaws.com'],
});

const deployRole = new iam.Role(this, 'GitHubDeployRole', {
  assumedBy: new iam.WebIdentityPrincipal(
    githubProvider.openIdConnectProviderArn,
    {
      StringEquals: {
        'token.actions.githubusercontent.com:aud': 'sts.amazonaws.com',
      },
      StringLike: {
        'token.actions.githubusercontent.com:sub':
          'repo:myorg/myrepo:ref:refs/heads/main', // Only main branch
      },
    },
  ),
});
```

```yaml
# .github/workflows/deploy.yml
name: Deploy
on:
  push:
    branches: [main]

permissions:
  id-token: write   # Required for OIDC
  contents: read

jobs:
  deploy:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - uses: aws-actions/configure-aws-credentials@v4
        with:
          role-to-assume: arn:aws:iam::123456789012:role/GitHubDeployRole
          aws-region: us-east-1

      - run: npx cdk deploy --require-approval never
```

Restrict the OIDC subject claim to specific branches, environments, or tags. Never use `repo:myorg/myrepo:*` — that allows any branch or PR to assume the role.

Configure retries and handle common AWS SDK errors properly.

```javascript
import { DynamoDBClient } from '@aws-sdk/client-dynamodb';
import { NodeHttpHandler } from '@smithy/node-http-handler';

// Configure client with retries and timeouts
const client = new DynamoDBClient({
  region: 'us-east-1',
  maxAttempts: 5, // Default is 3
  requestHandler: new NodeHttpHandler({
    connectionTimeout: 3000,
    socketTimeout: 3000,
  }),
  // Custom retry strategy
  retryStrategy: new ConfiguredRetryStrategy(
    5, // max attempts
    (attempt) => 100 * Math.pow(2, attempt), // Exponential backoff
  ),
});

// Error handling
try {
  await client.send(new GetItemCommand(params));
} catch (error) {
  switch (error.name) {
    case 'ResourceNotFoundException':
      // Table doesn't exist
      break;
    case 'ProvisionedThroughputExceededException':
      // Throttled — SDK already retried maxAttempts times
      break;
    case 'ConditionalCheckFailedException':
      // Condition expression not met (expected, not an error)
      break;
    case 'ValidationException':
      // Bad input — don't retry
      break;
    case 'InternalServerError':
      // AWS issue — retry with backoff
      break;
    default:
      // Check for transient network errors
      if (error.$retryable) {
        console.log('Retryable error:', error.message);
      }
      throw error;
  }
}
```

SDK v3 automatically retries on throttling and transient errors. Don't wrap every call in your own retry logic — you'll double the retries.

A Lambda function that checks daily AWS spend and sends Slack alerts when thresholds are exceeded.

```javascript
import { CostExplorerClient, GetCostAndUsageCommand } from '@aws-sdk/client-cost-explorer';

const ce = new CostExplorerClient({ region: 'us-east-1' }); // CE is always us-east-1

export const handler = async () => {
  const today = new Date();
  const startOfMonth = new Date(today.getFullYear(), today.getMonth(), 1)
    .toISOString().split('T')[0];
  const endDate = new Date(today.getTime() + 86400000)
    .toISOString().split('T')[0];

  // Get month-to-date spend
  const { ResultsByTime } = await ce.send(new GetCostAndUsageCommand({
    TimePeriod: { Start: startOfMonth, End: endDate },
    Granularity: 'MONTHLY',
    Metrics: ['UnblendedCost'],
    GroupBy: [{ Type: 'DIMENSION', Key: 'SERVICE' }],
  }));

  const groups = ResultsByTime[0]?.Groups || [];
  const totalCost = groups.reduce(
    (sum, g) => sum + parseFloat(g.Metrics.UnblendedCost.Amount), 0
  );

  const topServices = groups
    .map(g => ({
      service: g.Keys[0],
      cost: parseFloat(g.Metrics.UnblendedCost.Amount),
    }))
    .sort((a, b) => b.cost - a.cost)
    .slice(0, 5);

  const daysInMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0).getDate();
  const projectedCost = (totalCost / today.getDate()) * daysInMonth;

  // Alert if projected cost exceeds threshold
  const THRESHOLD = 500;
  if (projectedCost > THRESHOLD) {
    await sendSlackAlert({
      text: `AWS Cost Alert: Projected monthly spend $${projectedCost.toFixed(2)} exceeds $${THRESHOLD}`,
      fields: topServices.map(s => `${s.service}: $${s.cost.toFixed(2)}`),
    });
  }
};
```

Schedule with EventBridge: `rate(1 day)`. Cost Explorer API costs $0.01 per request — running daily is ~$0.30/month.

Generate presigned URLs for direct S3 uploads and downloads from a frontend, bypassing your API server for file transfer.

```javascript
import { S3Client, PutObjectCommand, GetObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';

const s3 = new S3Client({ region: 'us-east-1' });

// Generate upload URL (client uploads directly to S3)
export async function getUploadUrl(userId, filename, contentType) {
  const key = `uploads/${userId}/${Date.now()}-${filename}`;

  const url = await getSignedUrl(s3, new PutObjectCommand({
    Bucket: process.env.BUCKET_NAME,
    Key: key,
    ContentType: contentType,
    Metadata: { 'uploaded-by': userId },
    // Limit upload size to 10MB
    // Note: ContentLength conditions require presigned POST, not PUT
  }), {
    expiresIn: 300, // 5 minutes
  });

  return { url, key };
}

// Generate download URL
export async function getDownloadUrl(key, filename) {
  return getSignedUrl(s3, new GetObjectCommand({
    Bucket: process.env.BUCKET_NAME,
    Key: key,
    ResponseContentDisposition: `attachment; filename="${filename}"`,
  }), {
    expiresIn: 3600, // 1 hour
  });
}

// Frontend usage:
// const { url } = await fetch('/api/upload-url?filename=photo.jpg').then(r => r.json());
// await fetch(url, { method: 'PUT', body: file, headers: { 'Content-Type': file.type } });
```

For upload size limits, use presigned POST with conditions instead of presigned PUT. Presigned POST supports `content-length-range` conditions.
